class Solution:
    def getNthValue(self, M: int, N: int) -> int:
        # 前 M 项固定为 1 到 M
        nums = list(range(1, M + 1))

        # 如果第 N 项在前 M 项中，直接返回
        if N <= M:
            return nums[N - 1]

        # 从第 M+1 项开始模拟生成
        while len(nums) < N:
            window = nums[-M:]  # 取前面的 M 项

            # 记录是否有重复，同时维护最大值和最小值
            seen = set()
            has_dup = False
            mx = window[0]
            mn = window[0]

            for x in window:
                # 判断是否重复
                if x in seen:
                    has_dup = True
                seen.add(x)

                # 更新最大值和最小值
                if x > mx:
                    mx = x
                if x < mn:
                    mn = x

            # 按题意生成当前项
            if has_dup:
                nums.append(mx + mn)
            else:
                nums.append(mx - mn)

        return nums[N - 1]
```
