class Solution {
    public int getNthValue(int M, int N) {
        // 前 M 项固定为 1 到 M
        java.util.List<Integer> nums = new java.util.ArrayList<>();
        for (int i = 1; i <= M; i++) {
            nums.add(i);
        }

        // 如果第 N 项在前 M 项中，直接返回
        if (N <= M) {
            return nums.get(N - 1);
        }

        // 从第 M+1 项开始模拟生成
        while (nums.size() < N) {
            java.util.HashSet<Integer> seen = new java.util.HashSet<>();
            boolean hasDup = false;

            int mx = nums.get(nums.size() - M);
            int mn = nums.get(nums.size() - M);

            // 检查前面的 M 项
            for (int i = nums.size() - M; i < nums.size(); i++) {
                int x = nums.get(i);

                // 判断是否重复
                if (seen.contains(x)) {
                    hasDup = true;
                }
                seen.add(x);

                // 更新最大值和最小值
                if (x > mx) {
                    mx = x;
                }
                if (x < mn) {
                    mn = x;
                }
            }

            // 按题意生成当前项
            if (hasDup) {
                nums.add(mx + mn);
            } else {
                nums.add(mx - mn);
            }
        }

        return nums.get(N - 1);
    }
}
