class Solution {
public:
    int getNthValue(int M, int N) {
        // 前 M 项固定为 1 到 M
        std::vector<int> nums;
        for (int i = 1; i <= M; i++) {
            nums.push_back(i);
        }

        // 如果第 N 项在前 M 项中，直接返回
        if (N <= M) {
            return nums[N - 1];
        }

        // 从第 M+1 项开始模拟生成
        while ((int)nums.size() < N) {
            std::unordered_set<int> seen;
            bool hasDup = false;

            int start = nums.size() - M;
            int mx = nums[start];
            int mn = nums[start];

            // 检查前面的 M 项
            for (int i = start; i < (int)nums.size(); i++) {
                int x = nums[i];

                // 判断是否重复
                if (seen.count(x)) {
                    hasDup = true;
                }
                seen.insert(x);

                // 更新最大值和最小值
                if (x > mx) {
                    mx = x;
                }
                if (x < mn) {
                    mn = x;
                }
            }

            // 按题意生成当前项
            if (hasDup) {
                nums.push_back(mx + mn);
            } else {
                nums.push_back(mx - mn);
            }
        }

        return nums[N - 1];
    }
};
